import { BaseMoneyWorksRepository, SmartMoneyWorksClient } from '@moneyworks/data';
import { MoneyWorksInvoice } from '@moneyworks/canonical';
import { YYYYMMDD, Period, d } from '@moneyworks/utilities';

class InvoiceRepository extends BaseMoneyWorksRepository<MoneyWorksInvoice> {
  constructor(client: SmartMoneyWorksClient) {
    super(client, 'Transaction');
  }

  // Custom business methods
  async findOverdue(): Promise<MoneyWorksInvoice[]> {
    const today = d`${new Date()}`;
    return this.find({
      filter: `Type = "Invoice" AND DueDate < '${today}' AND AmountDue > 0`,
      orderBy: 'DueDate'
    });
  }

  async findByCustomer(customerCode: string): Promise<MoneyWorksInvoice[]> {
    return this.find({
      filter: `Type = "Invoice" AND NameCode = '${customerCode}'`,
      orderBy: 'TransDate DESC'
    });
  }

  async findByPeriod(period: Period): Promise<MoneyWorksInvoice[]> {
    return this.find({
      filter: `Type = "Invoice" AND Period = ${period}`
    });
  }

  // Add branded types in post-processing
  protected async postProcess(data: any): Promise<MoneyWorksInvoice> {
    return {
      ...data,
      TransDate: data.TransDate as YYYYMMDD,
      DueDate: data.DueDate as YYYYMMDD,
      Period: data.Period as Period,
      TransactionSeq: data.TransactionSeq as TransactionSeq
    };
  }

  // Prepare data for import
  protected prepareForImport(data: Partial<MoneyWorksInvoice>): any {
    return {
      ...data,
      Type: 'Invoice',
      Status: data.Status || 'Pending'
    };
  }
}

