import { MoneyWorksError } from '@moneyworks/data';

async function robustQuery(repository: any, params: any) {
  const maxRetries = 3;
  let lastError;

  for (let i = 0; i < maxRetries; i++) {
    try {
      return await repository.find(params);
    } catch (error) {
      lastError = error;

      if (error.code === 'ECONNREFUSED') {
        console.error('MoneyWorks server not running');
        throw error; // Don't retry connection errors
      }

      if (error.status === 401) {
        console.error('Authentication failed');
        throw error; // Don't retry auth errors
      }

      if (error.status === 503) {
        // Server busy, wait and retry
        const delay = Math.pow(2, i) * 1000; // Exponential backoff
        console.log(`Server busy, retrying in ${delay}ms...`);
        await new Promise(resolve => setTimeout(resolve, delay));
        continue;
      }

      // Unknown error, log and retry
      console.error(`Attempt ${i + 1} failed:`, error.message);
    }
  }

  throw lastError;
}

// Usage with error handling
try {
  const data = await robustQuery(repositories.taxRate, {
    filter: 'Rate1 > 10'
  });
  console.log(`Found ${data.length} tax rates`);
} catch (error) {
  if (error.code === 'ETIMEDOUT') {
    console.error('Query timed out - check network connection');
  } else {
    console.error('Query failed:', error.message);
  }
}
